mapper.select:
SELECT * FROM TB_MEMBER
WHERE WITHDRAW_YN = 'N'

    AND (MBR_NM LIKE CONCAT('%', #{searchKeyword}, '%') OR MBR_ID LIKE CONCAT('%', #{searchKeyword}, '%'))


    AND LOGIN_TYPE = #{loginType}

ORDER BY JOIN_DT DESC
LIMIT #{skip}, #{amount}

SELECT COUNT(MBR_SEQ) FROM TB_MEMBER WHERE WITHDRAW_YN = 'N'
AND (MBR_NM LIKE CONCAT('%', #{searchKeyword}, '%') OR MBR_ID LIKE CONCAT('%', #{searchKeyword}, '%'))
AND LOGIN_TYPE = #{loginType}

mapper.update:
UPDATE TB_MEMBER
SET PHONE = #{phone}, EMAIL = #{email}, PROFILE_IMG = #{profileImg},
    BIRTH_YEAR = #{birthYear}, GENDER = #{gender}, REGION1 = #{region1}, REGION2 = #{region2}
WHERE MBR_SEQ = #{mbrSeq}

UPDATE TB_MEMBER
SET WITHDRAW_YN = 'Y', WITHDRAW_DT = NOW()
WHERE MBR_SEQ = #{mbrSeq}

